/**
 * Migration Script: Convert existing pages to PageGroup system
 * Author: generated by Amazon Q
 * Created: 2024-01-20
 * Note: CommonJS version for Vercel deployment
 */

const { PrismaClient } = require('@prisma/client');

const prisma = new PrismaClient();

async function main() {
  console.log('🚀 Starting migration: Pages → PageGroups\n');

  try {
    // 1. دریافت تمام صفحات موجود
    const existingPages = await prisma.page.findMany({
      where: { pageGroupId: null },
      orderBy: { slug: 'asc' }
    });

    console.log(`📄 Found ${existingPages.length} pages without groups\n`);

    if (existingPages.length === 0) {
      console.log('✅ No pages to migrate. All done!');
      return;
    }

    // 2. گروهبندی صفحات بر اساس slug بدون prefix زبان
    const pagesBySlug = new Map();

    for (const page of existingPages) {
      // استخراج slug بدون prefix زبان (/en/home → home)
      const slugWithoutLang = page.slug.replace(/^\/(en|ar|fr|de|es)\//, '');
      
      if (!pagesBySlug.has(slugWithoutLang)) {
        pagesBySlug.set(slugWithoutLang, []);
      }
      pagesBySlug.get(slugWithoutLang).push(page);
    }

    console.log(`📁 Found ${pagesBySlug.size} unique page groups\n`);

    // 3. ایجاد PageGroup برای هر slug و اتصال صفحات
    let groupsCreated = 0;
    let pagesLinked = 0;

    for (const [slugWithoutLang, pages] of pagesBySlug.entries()) {
      // تشخیص default language (اولویت: en > ar > اولین زبان)
      const defaultPage = pages.find(p => p.language === 'en') 
        || pages.find(p => p.language === 'ar')
        || pages[0];

      const defaultLanguage = defaultPage.language;

      // استخراج نام گروه از title صفحه پیشفرض
      const groupName = defaultPage.title;

      console.log(`📦 Creating group: "${groupName}" (slug: ${slugWithoutLang})`);

      // ایجاد PageGroup
      const group = await prisma.pageGroup.create({
        data: {
          name: groupName,
          slug: slugWithoutLang,
          defaultLanguage: defaultLanguage
        }
      });

      groupsCreated++;

      // اتصال تمام صفحات به این گروه
      for (const page of pages) {
        await prisma.page.update({
          where: { id: page.id },
          data: {
            pageGroupId: group.id,
            isDefaultLang: page.language === defaultLanguage
          }
        });

        console.log(`  ├─ Linked: ${page.language.toUpperCase()} - ${page.slug} ${page.language === defaultLanguage ? '⭐' : ''}`);
        pagesLinked++;
      }

      console.log('');
    }

    console.log('✅ Migration completed successfully!\n');
    console.log(`📊 Summary:`);
    console.log(`   - Groups created: ${groupsCreated}`);
    console.log(`   - Pages linked: ${pagesLinked}`);

  } catch (error) {
    console.error('❌ Migration failed:', error);
    throw error;
  }
}

main()
  .catch((e) => {
    console.error('Error:', e);
    process.exit(1);
  })
  .finally(async () => {
    await prisma.$disconnect();
  });
